#include <stdio.h>
#include <time.h>

void log_error(const char *error_message) {
    time_t now;
    struct tm *timeinfo;
    char time_buffer[20];

    time(&now);
    timeinfo = localtime(&now);
    strftime(time_buffer, sizeof(time_buffer), "%Y-%m-%d %H:%M:%S", timeinfo);

    printf("[%s] ERROR: %s\n", time_buffer, error_message);
}